const record = $input.first().json;
const fields = record.fields || record;

const title = fields.Title || '';
const description = fields.Description || '';
const recordId = record.id || fields.RecordID || '';

// Parse structured data from description text
const nameMatch = description.match(/Name:\s*(.+)/i);
const emailMatch = description.match(/Email:\s*(\S+)/i);
const deadlineMatch = description.match(/Deadline:\s*(.+)/i);
const mediaMatch = description.match(/Media Outlet:\s*(.+)/i);
const categoryMatch = description.match(/Category:\s*(.+)/i);

const journalistName = (fields.Name || (nameMatch ? nameMatch[1].trim() : '')); 
const journalistEmail = (fields.Email || (emailMatch ? emailMatch[1].trim() : ''));
const deadline = (fields.Deadline || (deadlineMatch ? deadlineMatch[1].trim() : ''));
const mediaOutlet = mediaMatch ? mediaMatch[1].trim() : '';
const category = categoryMatch ? categoryMatch[1].trim() : '';

// Clean description - remove base64 junk
const cleanDescription = description.replace(/[A-Za-z0-9+/=]{100,}/g, '[content removed]');

// Auto-detect project
const text = (title + ' ' + cleanDescription).toLowerCase();
let project = 'GENERAL';
let projectContext = '';
let signature = '';

if (text.includes('health') || text.includes('medical') || text.includes('telemedicine') || 
    text.includes('doctor') || text.includes('patient') || text.includes('wellness') ||
    text.includes('therapy') || text.includes('mental health') || text.includes('healthcare')) {
  project = 'TM';
  projectContext = 'TeleMed Brasil - Leading telemedicine platform connecting patients with healthcare professionals across Brazil. Specializes in remote consultations, AI-powered health diagnostics, and healthcare accessibility.';
  signature = 'Ary Gustavo Ribeiro\nCEO, TeleMed Brasil\n+351 913 095 597\narygustavo@jcg.com.br\ntelemedbrasil.com';
} else if (text.includes('legal') || text.includes('law') || text.includes('court') || 
           text.includes('justice') || text.includes('judicial') || text.includes('attorney') ||
           text.includes('litigation') || text.includes('compliance')) {
  project = 'TJ';
  projectContext = 'TeleJud - Legal technology platform for the Brazilian judiciary. Pioneering AI-powered solutions for digital courts, case management, and access to justice.';
  signature = 'Ary Gustavo Ribeiro\nCEO, TeleJud\n+351 913 095 597\narygustavo@jcg.com.br\ntelejud.com';
} else if (text.includes('real estate') || text.includes('property') || text.includes('investment') || 
           text.includes('portugal') || text.includes('lisbon') || text.includes('golden visa') ||
           text.includes('relocation') || text.includes('expat') || text.includes('housing market')) {
  project = 'CL';
  projectContext = 'Casas de Lisboa - Premium real estate consultancy in Lisbon, Portugal. Specializes in property investment, Golden Visa program, European relocation services, and luxury real estate.';
  signature = 'Ary Gustavo Ribeiro\nCEO, Casas de Lisboa\n+351 913 095 597\narygustavo@jcg.com.br\ncasasdelisboa.com.br';
} else {
  project = 'GENERAL';
  projectContext = 'AI & Digital Innovation Consultant with 18+ years of experience in digital transformation, marketing automation, and AI implementation. Based in Berlin, working with companies across Europe and Latin America.';
  signature = 'Ary Gustavo Ribeiro\nAI & Digital Innovation Consultant\n+351 913 095 597\narygustavo@jcg.com.br';
}

return [{
  json: {
    record_id: recordId,
    title,
    description: cleanDescription,
    journalist_name: journalistName,
    journalist_email: journalistEmail,
    deadline,
    media_outlet: mediaOutlet,
    category,
    project,
    project_context: projectContext,
    signature
  }
}];

const aiResponse = $('Draft HARO Response').first().json.text || $('Draft HARO Response').first().json.response || '';
const data = $('Parse HARO Data').first().json;

// Parse subject and body from AI response
let subject = '';
let body = '';

const subjectMatch = aiResponse.match(/SUBJECT:\s*(.+?)(?:\n|$)/);
if (subjectMatch) {
  subject = subjectMatch[1].trim();
}

const bodyMatch = aiResponse.match(/BODY:\s*([\s\S]+)/);
if (bodyMatch) {
  body = bodyMatch[1].trim();
} else {
  // Fallback: everything after SUBJECT line
  body = aiResponse.replace(/SUBJECT:.*\n/, '').trim();
}

// Build full email draft
const greeting = data.journalist_name 
  ? `Hi ${data.journalist_name.split(' ')[0]},` 
  : 'Hi,';

const fullDraft = `${greeting}\n\n${body}\n\nBest regards,\n${data.signature}`;

return [{
  json: {
    record_id: data.record_id,
    subject: subject,
    body: fullDraft,
    project: data.project,
    journalist_name: data.journalist_name,
    journalist_email: data.journalist_email,
    deadline: data.deadline,
    title: data.title
  }
}];

